package worker

import "context"

func Start(ctx context.Context, jobs <-chan Job) {
	go func() {
		for {
			select {
			case <-ctx.Done():
				return
			case job := <-jobs:
				process(job)
			}
		}
	}()
}

type Job struct{}
func process(Job) {}
